class MyLinkedList {
public:
    MyLinkedList() {
    }

    int get(int index) {
        if (index < 0 || index >= size()) {
            return -1;
        }
        Node* current = head;
        for (int i = 0; i < index; i++) {
            current = current->next;
        }
        return current->data;
    }

    void addAtHead(int val) {
        Node* newNode = new Node;
        newNode->data = val;
        newNode->next = head;
        head = newNode;
    }

    void addAtTail(int val) {
        Node* newNode = new Node;
        newNode->data = val;
        if (tail == nullptr) {
            head = newNode;
        } else {
            tail->next = newNode;
            tail = newNode;
        }
    }

    void addAtIndex(int index, int val) {
        Node* newNode = new Node;
        newNode->data = val;
        if (index == 0) {
            newNode->next = head;
            head = newNode;
        } else if (index == size()) {
            newNode->next = tail;
            tail->prev = newNode;
        } else {
            Node* temp = head;
            for (int i = 0; i < index; i++) {
                temp = temp->next;
        }
        temp->next = newNode;
        newNode->prev = temp;
    }
}
};
